import React, { useState, useEffect } from 'react';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';

function TestHome() {
  const [markers, setMarkers] = useState([
    {
      id: 1,
      latitude: 55.751574,
      longitude: 37.573856,
      title: "Московский Кремль",
      description: "Исторический комплекс в центре Москвы",
      // Путь относительно папки public
      imageUrl: "/images/kremlin.jpg",
      type: "historic",
      color: "#FF0000",
      address: "Москва, Кремль"
    },
    {
      id: 2,
      latitude: 59.934280,
      longitude: 30.335098,
      title: "Эрмитаж",
      description: "Крупнейший художественный музей России",
      imageUrl: "/images/hermitage.jpg",
      type: "museum",
      color: "#0000FF",
      address: "Санкт-Петербург, Дворцовая площадь, 2"
    },
    {
      id: 3,
      latitude: 56.326887,
      longitude: 44.005986,
      title: "Нижегородский Кремль",
      description: "Крепость в историческом центре Нижнего Новгорода",
      imageUrl: "/images/nn_kremlin.jpg",
      type: "historic",
      color: "#00AA00",
      address: "Нижний Новгород, Кремль"
    }
  ]);

  // Структура папок в public:
  // public/
  //   images/
  //     kremlin.jpg
  //     hermitage.jpg
  //     nn_kremlin.jpg

  // Функция для безопасной загрузки изображений
  const getImageUrl = (path) => {
    // process.env.PUBLIC_URL нужен если проект развернут в поддиректории
    return `${process.env.PUBLIC_URL || ''}${path}`;
  };

  const generateBalloonContent = (marker) => {
    const fullImageUrl = getImageUrl(marker.imageUrl);

    return `
      <div style="max-width: 400px; font-family: Arial, sans-serif;">
        <div style="height: 200px; overflow: hidden; border-radius: 8px 8px 0 0;">
          <img 
            src="${fullImageUrl}" 
            alt="${marker.title}"
            style="width: 100%; height: 100%; object-fit: cover;"
            onerror="this.onerror=null; this.src='${process.env.PUBLIC_URL || ''}/images/default.jpg'"
          />
        </div>
        <div style="padding: 15px;">
          <h3 style="margin: 0 0 10px 0;">${marker.title}</h3>
          <p style="margin: 0 0 15px 0; color: #666;">${marker.description}</p>
          <div style="color: #888; font-size: 12px;">
            ${marker.latitude.toFixed(6)}, ${marker.longitude.toFixed(6)}
          </div>
        </div>
      </div>
    `;
  };

  return (
    <div style={{ width: '100%', height: '600px' }}>
      <YMaps>
        <Map 
          state={{ center: [55.751574, 37.573856], zoom: 10 }} 
          width="100%" 
          height="100%"
        >
          {markers.map((marker) => (
            <Placemark
              key={marker.id}
              geometry={[marker.latitude, marker.longitude]}
              options={{
                iconLayout: 'default#image',
                iconImageHref: `${process.env.PUBLIC_URL || ''}/icons/marker-${marker.type}.svg`,
                iconImageSize: [40, 40],
                iconImageOffset: [-20, -40],
              }}
              properties={{
                balloonContent: generateBalloonContent(marker),
              }}
            />
          ))}
        </Map>
      </YMaps>
    </div>
  );
}

export default TestHome;
